class Solution:
    def canChange(self, start: str, target: str) -> bool:
        i, j = 0, 0
        while i < len(start) and j < len(target):
            if start[i] == target[j]:
                i += 1
                j += 1
            elif start[i] == 'L' and i > 0 and start[i-1] == '_':
                i += 1
            elif start[i] == 'R' and i < len(start) - 1 and start[i+1] == '_':
                i += 1
            elif start[i] == '_' and target[j] in ['L', 'R']:
                return False
            else:
                return False
        return i == len(start) and j == len(target)
